(246, NULL, 'Alaska', 'Alaska Digital Academy (AkDA)', '6-12', 'Open statewide; must fulfill district agreements; must complete assignments; teacher interaction.', NULL, NULL, 'https://www.alaskadigitalacademy.org/', 'Academic Program', 'STEM', 'Outside School', 'Online / remote; flexible schedule; helps students in remote areas; college preparatory.', '2025-11-11 22:01:54', '2025-11-24 22:17:38'),
(247, NULL, 'Alaska', 'Alaska Geographic Youth Expeditions (Teen Expeditions)', '6-12', 'Must be Alaska resident teen; must meet the age condition for a given trip; no required prior outdoor experience; physical fitness / general good health required; application plus a nominator (someone (teacher / youth leader) must nominate student) is required.', NULL, NULL, 'https://www.akgeo.org/youth-programs/youth-expeditions/', 'Academic Program', 'Science', 'Outside School', 'In‑person, camping / expedition format; trips often in remote or back‑country settings; physical demands; good for leadership, environmental / ecological learning; high value due to “no cost” for participants; selective in that nomination + application required.', '2025-11-11 22:01:54', '2025-11-11 22:01:54'),
(248, NULL, 'Alaska', 'Alaska Native Heritage Center Internships', '6-12', 'Applicants must be youth; preference given to Alaska Native youth; some roles require familiarity with Native culture; sometimes little or no prior job experience required.', NULL, NULL, 'https://www.alaskanative.net/visit/school-visits/', 'Program', 'Social Studies & Humanities', 'Outside School', 'Selective in that youth are expected to commit; travel may or may not be needed depending on where you live; roles cover cultural performance, tourism, guest services, storytelling, etc.; offers real work‑experience; prestige within cultural/tourism & Native arts contexts.', '2025-11-11 22:01:54', '2025-11-24 22:18:02'),
(251, NULL, 'Alaska', 'High School Internships – Alaska Songbird Institute', '9-12', 'Ages 14‑18; interest in research / wildlife; letters of recommendation; available to in‑state due to housing/transport constraints.', 0.00, NULL, 'https://aksongbird.org/get-involved/high-school-internships/', 'Program', 'Science', 'Outside School', 'Field‑work; selective; requires commitment; good for students interested in ecology / field science.', '2025-11-11 22:01:54', '2025-11-11 22:01:54'),
(252, NULL, 'Alaska', 'Junior Science & Humanities Symposium (Alaska JSHS)', '9-12', 'Must conduct original STEM research; enrollment in public/private/home school; application.', NULL, NULL, 'https://www.jshs.org/region/alaska/', 'Competition', 'Science', 'Outside School', 'Prestige: USA links; opportunity to win scholarships; presentation experience.', '2025-11-11 22:01:54', '2025-11-11 22:01:54'),
(253, NULL, 'Alaska', 'Native Youth Olympics (NYO) / Junior NYO', '7-12', 'In‑state students; limited number per school per event; physical performance & interest.', NULL, NULL, 'https://nyogames.com/nyo-games/', 'Competition', 'Athletics/Sports', 'Outside School', 'High prestige in cultural & athletic tradition; travel required; encourages cultural heritage & physical fitness; online resources for training.', '2025-11-11 22:01:54', '2025-11-24 22:18:47'),
(254, NULL, 'Alaska', 'STEM Scouts (Great Alaska Council)', '6-12', 'Open to youth in Scouting units; modules; open participation.', NULL, NULL, 'https://scoutingalaska.org/stem-scouts/', 'Club', 'STEM', 'Outside School', 'Offers badges, experiential learning; online & field‑trip components.', '2025-11-11 22:01:54', '2025-11-24 22:18:57'),
(257, NULL, 'Arizona', '4‑H STEM YOUniversity (AZ)', '6-12', 'Be enrolled or affiliated with Arizona 4‑H; interest in STEM', NULL, NULL, 'https://extension.arizona.edu/4-h-stem', 'Club', 'STEM', 'Outside School', 'Multiple modules (robotics, under‑water robotics, challenge, ambassadors)', '2025-11-11 22:01:54', '2025-11-24 22:19:31'),
