(489, NULL, 'Maine', 'Maine Girls Collaborative Project', '6-12', 'Girls in Maine.', NULL, NULL, 'https://pathwaystoscience.org/maine.aspx?sort=programs&subsort=usergroup&subsubsort=HighSchool_High+School+Students', 'Program', 'STEM', 'Outside School', 'A project that brings together organizations committed to informing and motivating girls to pursue STEM careers.', '2025-11-11 22:01:54', '2025-11-11 22:01:54'),
