(493, NULL, 'Maine', 'Maine STEM Collaborative', '6-12', 'Maine students.', NULL, NULL, 'https://pathwaystoscience.org/maine.aspx?sort=programs&subsort=usergroup&subsubsort=HighSchool_High+School+Students', 'Program', 'STEM', 'At School', 'A statewide movement with the goal of ensuring Maine students have essential STEM knowledge and skills.', '2025-11-11 22:01:54', '2025-11-11 22:01:54'),
(495, NULL, 'Maryland', 'Associate of Arts (AAT) Program', '9-12', 'Students interested in pursuing a teaching career.', NULL, NULL, 'https://teach.maryland.gov/Pages/Current-High-School-Student.aspx', 'Academic Program', 'Arts', 'At School', 'This program is offered at Maryland\'s two-year community colleges and is designed to link up with four-year teacher preparation programs.', '2025-11-11 22:01:54', '2025-11-24 22:52:58'),
(497, NULL, 'Maryland', 'Homework Club I', '6', 'Students living in Kimberly Gardens, a low-income residential complex.', NULL, NULL, 'https://risefirst.org/resources/resource-directory?location=Maryland&life_stage=High%20School%20Student&category=Program', 'Program', 'General Academic', 'At School', 'This program is staffed by certified teachers who provide homework assistance and academic support.', '2025-11-11 22:01:54', '2025-11-24 20:20:19'),
(498, NULL, 'Maryland', 'Homework Club II', '7-12', 'Students living in Kimberly Gardens, a low-income residential complex.', NULL, NULL, 'https://risefirst.org/resources/resource-directory?location=Maryland&life_stage=High%20School%20Student&category=Program', 'Program', 'General Academic', 'At School', 'This program is staffed by certified teachers who provide homework assistance and academic support.', '2025-11-11 22:01:54', '2025-11-24 22:52:45'),
(499, NULL, 'Maryland', 'Kennedy Krieger School Programs', '6-12', 'Students with complex disabilities, including learning challenges and autism spectrum disorders.', NULL, NULL, 'https://www.kennedykrieger.org/schools-and-education', 'Academic Program', 'General Academic', 'At School', 'These schools provide instruction that focuses on the development of academic, social, emotional, and behavioral skills.', '2025-11-11 22:01:54', '2025-11-24 22:53:17'),
(501, NULL, 'Maryland', 'Maryland Leadership Workshops (MLW)', '6-8', 'Students must be residents of Louisiana.', NULL, NULL, 'https://www.gfs.org/academics/upper-school/enrichment-opportunities', 'Academic Program', 'Leadership & Community Service', 'Outside School', 'These are week-long residential leadership development programs for middle and high school students. This is a flagship statewide program.', '2025-11-11 22:01:54', '2025-11-24 22:53:31'),
(503, NULL, 'Maryland', 'Meals on Wheels - Meal Delivery', '9-12', '• Be 18 years of age or accompanied by an adult/ guardian.\r\n• Hold a valid driver’s license.\r\n• Have access to your own reliable vehicle.\r\n• Pass a background check', NULL, NULL, 'https://mealsonwheelsmd.org/volunteer/meal-delivery/', 'Program', 'Leadership & Community Service', 'Outside School', '• Students deliver food door to door to disabled individuals\r\n• There is no specific grade range specified in the page, but since the requirements ask for a driver\'s license, I\'m assuming the student needs to be at least in HS', '2025-11-11 22:01:54', '2025-11-24 22:53:42'),
(506, NULL, 'Maryland', 'Public Service Internship', '9-12', 'High school seniors in Maryland\'s Second Congressional District who are participating in a school-sponsored work/study program.', NULL, NULL, 'https://www.gfs.org/academics/upper-school/enrichment-opportunities', 'Program', 'Leadership & Community Service', 'Outside School', 'This program gives exceptional students a hands-on experience in public service and the legislative process.', '2025-11-11 22:01:54', '2025-11-24 22:53:54'),
(507, NULL, 'Maryland', 'Snider Enterprise and Leadership Fellows (SELF)', '9-12', 'Innovative and motivated high school students.', NULL, NULL, 'https://www.gfs.org/academics/upper-school/enrichment-opportunities', 'Academic Program', 'Business & Entrepreneurship', 'Outside School', 'An inspiring and unique summer program that empowers students to explore solutions to problems they are passionate about. This is a flagship statewide program.', '2025-11-11 22:01:54', '2025-11-24 22:54:01'),
(509, NULL, 'Maryland', 'TalentReady', '8', '• Only rising 9th grade students may apply.\r\n• GPA (2.50+)\r\n• Interested in Information Technology \r\n• Essay\r\n• Two teacher references\r\n• Must have attended the Summer Bridge Program previously', NULL, NULL, 'https://www.pgcps.org/offices/career-and-technical-education/talent-ready', 'Academic Program', 'STEM', 'Through School', 'The program prepares the student for\r\n a career in either software development, networking, data management, or cybersecurity.', '2025-11-11 22:01:54', '2025-11-24 20:22:38'),
(510, NULL, 'Maryland', 'Teacher Academy of Maryland (TAM)', '9-12', 'Students interested in exploring a career in education.', NULL, NULL, 'https://teach.maryland.gov/Pages/Current-High-School-Student.aspx', 'Academic Program', 'General Academic', 'At School', 'This program offers opportunities for students to learn about teaching and participate in an education internship.', '2025-11-11 22:01:54', '2025-11-24 22:54:13'),
