(755, NULL, 'Pennsylvania', 'Engineering Summer Academy at Penn (ESAP)', '9-12', 'GPA ≥ 3.0; age ≥ 15', 0.00, NULL, 'https://www.ladderinternships.com/ladder-research-opportunities-for-high-school-students-in-pennsylvania-pa', 'Academic Program', 'STEM', 'Outside School', 'Interns are matched with high-growth startups and mentored by professionals (ex-Google, McKinsey, etc.); projects include building AI models, business plans, and go-to-market strategies; strong emphasis on college readiness and real-world experience', '2025-11-11 22:01:55', '2025-11-24 21:19:49'),
(758, NULL, 'Pennsylvania', 'Lumiere Research Scholar Program', '9-12', 'Open to students in Pennsylvania and worldwide; selective admissions process; no prior research experience required', 0.00, NULL, 'https://www.lumiere-education.com/', 'Academic Program', 'General Academic', 'Outside School', 'includes writing support and optional publication; projects culminate in a 15-page paper and presentation at Lumiere Research Symposium;', '2025-11-11 22:01:55', '2025-11-24 21:21:14'),
(760, NULL, 'Pennsylvania', 'PA HOSA (Health Occupations Students of America)', '6-12', 'Must be enrolled in a participating school with a HOSA chapter or join the Virtual Chapter; students must be in a health science or related career pathway', 0.00, NULL, 'https://pahosa.org/', 'Competition', 'Science', 'At School', 'students compete in over 50 events including CPR, medical math, health career display, and biomedical debate; Penn HOSA Foundation awards $2,000–$5,000 scholarships to graduating seniors pursuing healthcare careers', '2025-11-11 22:01:55', '2025-11-24 21:21:22'),
(772, NULL, 'Rhode Island', '21st Century Community Learning Centers (21st CCLC)', '6-12', 'Students attending Title I schools or schools in high-poverty areas;', NULL, NULL, 'https://ride.ri.gov/students-families/education-programs/after-school-21st-century-clcs', 'Academic Program', 'General Academic', 'At School', 'includes homework help, STEM clubs, arts, physical activity, and family events;', '2025-11-11 22:01:55', '2025-11-24 21:24:58'),
(773, NULL, 'Rhode Island', 'AS220 Youth', '9-12', 'Open to all youth in Rhode Island; special focus on youth in state care, custody, or juvenile detention;', NULL, NULL, 'https://as220.org/youth/', 'Program', 'Arts', 'Outside School', 'Youth-led and inspired by hip hop culture; includes mentorship, technical training, and career-building; annual showcase “Futureworlds” blends art, activism, and Afrofuturism', '2025-11-11 22:01:55', '2025-11-11 22:01:55'),
(774, NULL, 'Rhode Island', 'Freedom Dreams & Throughline Learning', '6-12', 'Open to schools, districts, nonprofits, and community groups seeking to dismantle systemic inequities.', NULL, NULL, 'https://www.freedomdreams.info/ and https://throughlinelearning.org/', 'Academic Program', 'General Academic', 'At School', 'Freedom Dreams focuses on dismantling systemic inequities through community-based design and educator support; Throughline Learning offers professional development, tutoring frameworks, and AI policy guidance;', '2025-11-11 22:01:55', '2025-11-24 21:25:10'),
(775, NULL, 'Rhode Island', 'Learn365RI', '6-12', 'Open to all Rhode Island students; specific programs may target Title I schools, chronically absent students, or those needing academic support', NULL, NULL, 'https://ride.ri.gov/information-accountability/ri-education-data/learn-365-ri', 'Academic Program', 'General Academic', 'At School', 'aims to improve RICAS scores, reduce chronic absenteeism, and increase FAFSA completion; includes summer camps, tutoring, art projects, and career exploration; interactive map available for program locations', '2025-11-11 22:01:55', '2025-11-24 21:25:20'),
