(863, NULL, 'Vermont', 'Talent Search', '7-12', 'attend a VSAC-partnered school, express motivation for postsecondary education, meet federal low-income guidelines, and often be a potential first-generation college student', NULL, NULL, 'https://www.vsac.org/about/our-outreach-programs/talent-search', 'Program', 'General Academic', 'Outside School', 'The VSAC Talent Search program helps students to explore career and postsecondary education options, to succeed in and to graduate from high school, and to enroll in education programs after high school.', '2025-11-11 22:01:55', '2025-11-24 21:54:21'),
(864, NULL, 'Vermont', 'Upward Bound', '9-12', 'Neither parent has completed a bachelor\'s degree or the family is low to moderate income.', NULL, NULL, 'https://www.castleton.edu/directory/offices-services-directory/upward-bound', 'Academic Program', 'General Academic', 'Outside School', 'Upward Bound is a federally funded TRIO program that offers challenging pre-college experiences to students of high academic ability with a goal of completing a four-year college degree. Its goal is to generate skills and motivation necessary for success in high school and college through an academic year program with weekly and monthly individual and group meetings, and an intensive six-week summer residential program that includes credited college coursework.', '2025-11-11 22:01:55', '2025-11-24 21:54:35'),
(866, NULL, 'Vermont', 'VSAC GEAR UP (Gaining Early Awareness and Readiness for Undergraduate Programming)', '6-12', 'grades 6-12 and meet one or more of several criteria: being eligible for Free and Reduced-Price Lunch, being a first-generation college student, being an English language learner, experiencing homelessness or foster care, or having an incarcerated parent.', NULL, NULL, 'https://www.vsac.org/about/our-outreach-programs/gear-up', 'Program', 'General Academic', 'Outside School', 'VSAC GEAR UP Outreach counselors provide individual, small group, and whole grade meetings in support of students’ college and career goals.', '2025-11-11 22:01:55', '2025-11-24 21:55:06'),
