(995, NULL, 'Colorado', 'Degree Start by  pikes pike college', '11-12', '(for English)Accuplacer Writing 246 PSAT/SAT EBWR 470 ACT Reading: 17(for Math)Accuplacer Algebra, and Statistics 240 PSAT/SAT Math 500 ACT 19', NULL, '2025-06-15', 'https://www.pikespeak.edu/academics/high-school-programs/Degree-Start.php', 'Scholarship', 'Social Studies & Humanities', 'Outside School', 'Degree Start is a pilot program for rising Junior and Senior high school students majoring in a liberal arts field.. There are', '2025-11-13 21:31:08', '2025-11-24 22:33:14'),
(996, NULL, 'Colorado', 'High School Program by the University of Colorado Denver', '9-12', 'your parents cannot have a college degree, or must be a single-parent household. or be the eldest', NULL, '2025-09-01', 'https://www.ucdenver.edu/pre-college/programs/high-school', 'Scholarship', 'General Academic', 'Outside School', 'This program is designed for students who are going on to college after high school. For eligibility, they must be in high school and first-generation college student, meaning neither of their biological nor adoptive parents completed a four-year college degree. And have a gpa over 2.5. the main aim of the program is to help students go to college .and can even get some college credit', '2025-11-13 21:31:08', '2025-11-24 22:33:25'),
(997, NULL, 'Colorado', 'K-12 Summer Programs by  Colorado State University', '6-12', 'must be at grade level', NULL, '2025-09-01', 'https://k12summer.colostate.edu/', 'Academic Program', 'Science', 'Outside School', 'It\'s a summer camp for students to get ahead in their classes. If the student is in highschool, they can gain college credit by joining some of these programs. it covers STEM classes.', '2025-11-13 21:31:08', '2025-11-24 19:54:12'),
(998, NULL, 'Colorado', 'MATHCOUNTS Colorado', '6-8', 'Middle school; school registration required', 0.00, '2025-09-01', 'https://mathcounts.coloradomath.org/', 'Competition', 'Math', 'At School', 'USA middle-school math competition with CO chapters', '2025-11-13 21:31:08', '2025-11-24 19:54:22'),
(999, NULL, 'Colorado', 'Nita M. Lowey 21st Century Community Learning Centers (CCLC) and Out-of-School Time Programs', '6-12', 'if you are enrolled in a low income school', NULL, '2025-09-01', 'https://www.cde.state.co.us/studentsupport/21stcclc', 'Academic Program', 'Math', 'Outside School', 'This program is designed for low-income students to improve their grades through out-of-school help including youth development activities, service counseling programs, technology education, environmental and financial literacy programs, STEM, career and technical programs, internship or apprenticeship programs, and other ties to an in-demand sector for participating students. overall for most students had a GPA improvment.', '2025-11-13 21:31:08', '2025-11-24 19:54:30'),
(1000, NULL, 'Colorado', 'Soifer Mathematical Olympiad (UCCS)', '6-12', 'Open to Colorado students; registration required', NULL, '2025-09-01', 'https://soifermathematicalolympiad.uccs.edu/', 'Competition', 'Math', 'Outside School', 'Individual math contest organized by UCCS', '2025-11-13 21:31:08', '2025-11-24 19:54:40'),
(1001, NULL, 'Connecticut', 'ConnCAP', '9-12', 'Students from low‑income families or where neither parent has a 4‑year college degree; specific middle schools', NULL, '2025-06-01', 'https://caps.center.uconn.edu/programs/college-access-programs/conncap/?utm_source=chatgpt.com', 'Academic Program', 'General Academic', 'Through School', 'The UConn Connecticut Collegiate Awareness and Preparation (ConnCAP) program motivates and prepares Connecticut students from underserved communities with potential for success, in grades 9-12 and at the post-secondary level.', '2025-11-13 21:31:08', '2025-11-24 22:34:07'),
(1002, NULL, 'Connecticut', 'High School Student Research Apprentice Program', '11', 'B average Family must be low income', NULL, '2025-04-01', 'https://health.uconn.edu/hcop/pathway-programs/high-school-student-research-apprentice-program/', 'Academic Program', 'Science', 'Outside School', 'Five-week summer program for 11th grade students interested in medicine, dental medicine or biomedical research, providing students with a research experience in one of the basic science or clinical laboratories with an earned stipend', '2025-11-13 21:31:08', '2025-11-24 22:34:25'),
(1003, NULL, 'Connecticut', 'HMTCA-Trinity Partnership', '11-12', 'students must have a 3.0 GPA or higher, submit high school transcript, letter of recommendation, and have the high school counselor\'s approval', NULL, '2025-09-01', 'https://www.trincoll.edu/cher/hmtca/', 'Academic Program', 'Social Studies & Humanities', 'Outside School', 'HMTCA has a long-standing partnership with Trinity College where students have enrolled in courses ranging from Calculus I, II, and III and introductory courses in Psychology, Philosophy, Sociology, Music, English Literature, Computer Science, Chemistry, Classics, Spanish, and Japanese', '2025-11-13 21:31:08', '2025-11-24 22:34:35'),
(1004, NULL, 'Connecticut', 'Internship Opportunities', '8-12', 'must be in highschool', NULL, '2025-01-01', 'https://www.newhavenct.gov/government/departments-divisions/human-resources/looking-for-a-job/internship-opportunities', 'Program', 'Business & Entrepreneurship', 'Outside School', 'The City’s employment of students takes place through the Student Intern Program. Internships provide valuable work experience directly related to the student\'s academic field of study. Participants will be given high-level work experience that may prepare them for permanent positions in the workforce. they get pain while getting experience.', '2025-11-13 21:31:08', '2025-11-24 22:34:54'),
(1005, NULL, 'Connecticut', 'Missoula Children\'s Theatre', '6-12', 'none', 0.00, '2025-01-27', 'https://quickcenter.fairfield.edu/education/missoula-childrens-theatre/index.html?_gl=1*1e8i45r*_gcl_au*MjA1Njk2MTg4LjE3NjAxMjEwNDg.', 'Program', 'Arts', 'Outside School', 'summer theatre program offers six sessions and   A total of 60 community children, grades 1-12, may be registered in each weekly session.', '2025-11-13 21:31:08', '2025-11-24 19:55:35');
